  "for": "a person",
  "to": "attend a family mediation information and assessment meeting",
  "conditions": [
    {
      "type": "BEFORE",
      "text": "making a relevant family application",
      "section": "https://www.legislation.gov.uk/ukpga/2014/6/section/10"
    }
  ],
