}

{
  "main_section": "https://www.legislation.gov.uk/ukpga/2014/6/section/13",
  "type": "PROHIBITED",
  "for": "A person",
  "to": "without the permission of the court instruct a person to provide expert evidence for use in children proceedings.",
  "conditions": [],
  "_alt_section_urls": [
    "https://www.legislation.gov.uk/ukpga/2014/6/section/10"
  ]
