{
  "main_section": "https://www.legislation.gov.uk/ukpga/2014/6/section/13",
  "type": "PROHIBITED",
  "for": "A person",
  "to": "in children proceedings, without the permission of the court put expert evidence (in any form) before the court.",
  "conditions": [],
  "_alt_section_urls": [
    "https://www.legislation.gov.uk/ukpga/2014/6/section/10"
  ]
}

{
  "main_section": "https://www.legislation.gov.uk/ukpga/2014/6/section/13",
  "type": "PERMITTED",
  "for": "a court",
  "to": "give permission as mentioned in subsection (1), (3) or (5)",
  "conditions": [
    {
      "type": "ONLY IF",
      "text": "the court is of the opinion that the expert evidence is necessary to assist the court to resolve the proceedings justly.",
      "section": "https://www.legislation.gov.uk/ukpga/2014/6/section/13"
    }
  ],
  "_alt_section_urls": [
    "https://www.legislation.gov.uk/ukpga/2014/6/section/14",
    "https://www.legislation.gov.uk/ukpga/2014/6/section/1"
  ]
}

{
  "main_section": "https://www.legislation.gov.uk/ukpga/2014/6/section/13",
  "type": "OBLIGATORY",
  "for": "a court",
  "to": "have regard in particular to— (a) any impact which giving permission would be likely to have on the welfare of the children concerned, including in the case of permission as mentioned in subsection (3) any impact which any examination or other assessment would be likely to have on the welfare of the child who would be examined or otherwise assessed, (b) the issues to which the expert evidence would relate, (c) the questions which the court would require the expert to answer, (d) what other expert evidence is available (whether obtained before or after the start of proceedings), (e) whether evidence could be given by another person on the matters on which the expert would give evidence, (f) the impact which giving permission would be likely to have on the timetable for, and duration and conduct of, the proceedings, (g) the cost of the expert evidence, and (h) any matters prescribed by Family Procedure Rules",
  "conditions": [
    {
      "type": "WHEN/IF/WHERE",
      "text": "deciding whether to give permission as mentioned in subsection (1), (3) or (5)",
      "section": "https://www.legislation.gov.uk/ukpga/2014/6/section/13"
    }
  ],
  "_alt_section_urls": [
    "https://www.legislation.gov.uk/ukpga/2014/6/section/11",
